INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('claração periódica de rendimentos do exercício a que respeita o imposto, que, em consequência da suspensão da terceira entrega por conta prevista no número anterior, deixou de ser paga uma importância superior a 20  da que, em condições normais, teria sido entregue, há lugar a juros compensatórios desde o termo do prazo em que a entrega deveria ter sido efetuada até ao termo do prazo para o envio da declaração ou até à data do pagamento da autoliquidação, se anterior. 
