INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('00 nos termos do protocolo de cedência de colaboradores entre o Turismo de Portugal, I. P., e para a Agência para o Investimento e Comércio Externo de Portugal, E. P. E. (AICEP, E. P. E.), destinada à promoção de Portugal no exterior, nos termos a contratualizar entre as duas entidades. 
